	{
        if (pa[i] && pb[i])
		{
            e++;
        }
		else if (pa[i])
		{
            ma++;
        }
		else if (pb[i])
		{
            mb++;
        }
		else
		{
            return false;
        }
    }
    if (ma > k / 2 || mb > k / 2)
	{
        return false;
    }
    int r = k - (ma + mb);
    if (r > e) {
        return false;
    }
    return true;
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);cout.tie();
    int T;
    cin >> T;
    while (T--)
	{
        int n, m, k;
